onClick:
{{
  !tblIngredientsList.selectedRow?.id

    ? showAlert("Select an ingredient first", "warning")

    : (
        resetWidget("inpIngEditIngredient"),
        resetWidget("inpIngEditSupplierCode"),
        resetWidget("selIngEditCategory"),
        resetWidget("selIngEditSupplier"),
        resetWidget("selIngEditPackaging"),
        resetWidget("inpIngEditQuantity"),
        resetWidget("selIngEditPurchaseUnit"),
        resetWidget("inpIngEditPurchaseCost"),
        resetWidget("inpIngEditWastage"),
        resetWidget("msIngEditAllergens"),
        resetWidget("msIngEditDietTags"),
        resetWidget("rteIngEditNotes"),

        getIngredientById.run(() => {

          getEditIngredientAllergenIds.run(() => {

            getEditIngredientDietTagIds.run(() => {

              showModal("mdlEditIngredient");

            });

          });

        })
      )
}}
